 3	namespace App\Http\Middleware;
 4	
 5	use App\Support\Auth\UserAccessService;
 6	use Closure;
 7	use Illuminate\Http\Request;
 8	use Symfony\Component\HttpFoundation\Response;
 9	
10	class EnsurePermission
11	{
12	    public function __construct(
13	        private readonly UserAccessService $accessService
14	    ) {
15	    }
16	
17	    public function handle(Request $request, Closure $next, string $permissions): Response
18	    {
19	        $user = $request->user();
20	        if ($user === null) {
21	            return response()->json(['message' => 'Unauthenticated.'], 401);
22	        }
23	
24	        $required = array_values(array_filter(array_map(
25	            fn (string $value): string => trim($value),
26	            explode('|', $permissions)
27	        )));
28	
29	        if ($required === []) {
30	            return $next($request);
31	        }
32	
33	        $userId = (int) ($user->id ?? 0);
34	        if ($userId <= 0) {
35	            return response()->json(['message' => 'Unauthenticated.'], 401);
36	        }
37	
38	        foreach ($required as $permission) {
39	            if ($this->accessService->hasPermission($userId, $permission)) {
40	                return $next($request);
41	            }
42	        }
43	
44	        return response()->json([
45	            'message' => 'This action is unauthorized.',
46	        ], 403);
47	    }
48	}
